      { approach: '산화물계 전해질', patents: 876, coverage: 0.71, evidence: 'H01M 10/052' },
      { approach: '폴리머 복합 전해질', patents: 432, coverage: 0.55, evidence: 'H01M 10/056' },
    ],
  },
  TPI: null,
  FSS: null,
  WSD: null,
};

export const useTGIPStore = create((set, get) => ({
  // Global
  selectedTechnology: null,
  selectedView: 'RTS',
  analysisRunId: null,

  // Results
  results: { RTS: null, TPI: null, FSS: null, WSD: null },

  // Evidence
  evidence: {
    representativePatents: [],
    ipcSignatures: [],
    abstractSnippets: [],
    confidenceScores: {},
  },

  // UI State
  isRunning: false,
  evidenceDrawerOpen: false,
  error: null,

  // Actions
  setTechnology: (tech) => set({
    selectedTechnology: tech,
    results: { RTS: null, TPI: null, FSS: null, WSD: null },
    evidence: { representativePatents: [], ipcSignatures: [], abstractSnippets: [], confidenceScores: {} },
    analysisRunId: null,
    error: null,
  }),

  setView: (view) => set({ selectedView: view }),

  toggleEvidenceDrawer: () => set((s) => ({ evidenceDrawerOpen: !s.evidenceDrawerOpen })),

  openEvidenceDrawer: () => set({ evidenceDrawerOpen: true }),

  runAnalysis: async (tgipApi) => {
    const { selectedTechnology } = get();
    if (!selectedTechnology) return;

    set({ isRunning: true, error: null });
    try {
      const response = await tgipApi.runAnalysis(selectedTechnology.id);
      const { run_id, results, evidence } = response.data;
      set({
        analysisRunId: run_id,
        results,
        evidence,
        isRunning: false,
        evidenceDrawerOpen: true,
      });
    } catch {
      // 백엔드 미구현 시 Mock 데이터 사용
      const mockRunId = `mock-run-${Date.now()}`;
      set({
        analysisRunId: mockRunId,
        results: MOCK_RESULTS,
        evidence: MOCK_EVIDENCE,
        isRunning: false,
        evidenceDrawerOpen: true,
      });
    }
  },
}));

