      {VIEWS.map((v) => {
        const isActive = selectedView === v.id;
        const hasData = !!results?.[v.id];

        return (
          <button
            key={v.id}
            onClick={() => v.available && setView(v.id)}
            disabled={!v.available}
            className={`
              mx-2 rounded-lg px-3 py-3 text-left transition-all
