            <Route path="/" element={<LandingPage />} />
            <Route path="/login" element={<Login />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </>
        )}
      </Routes>
    </Router>
  );
};

const App = () => {
  return (
    <AuthProvider>
      <NotificationsProvider>
        <AppContent />
        <ToastContainer position="top-right" duration={5000} />
      </NotificationsProvider>
    </AuthProvider>
  );
}

export default App;

