    18→  const [open, setOpen] = useState(false);
    19→  const [loading, setLoading] = useState(false);
    20→  const ref = useRef(null);
    21→
    22→  useEffect(() => {
    23→    if (selectedTechnology) setQuery(selectedTechnology.name);
    24→  }, [selectedTechnology]);
    25→
    26→  useEffect(() => {
    27→    const handler = (e) => { if (!ref.current?.contains(e.target)) setOpen(false); };
    28→    document.addEventListener('mousedown', handler);
    29→    return () => document.removeEventListener('mousedown', handler);
    30→  }, []);
    31→
    32→  useEffect(() => {
    33→    if (!query || query === selectedTechnology?.name) { setResults([]); return; }
    34→    const timer = setTimeout(async () => {
    35→      setLoading(true);
    36→      try {
