    65→          className="flex-1 text-sm outline-none placeholder:text-slate-400 text-slate-800"
    66→          placeholder="Select technology..."
    67→          value={query}
    68→          onChange={(e) => setQuery(e.target.value)}
    69→          onFocus={() => !selectedTechnology && setResults(MOCK_TECHNOLOGIES) || setOpen(true)}
    70→        />
    71→        {loading && (
    72→          <div className="w-3 h-3 border-2 border-slate-300 border-t-slate-600 rounded-full animate-spin" />
    73→        )}
    74→      </div>
    75→
    76→      {open && results.length > 0 && (
    77→        <div className="absolute top-full mt-1 left-0 w-80 bg-white border border-slate-200 rounded-lg shadow-lg z-50">
    78→          {results.map((tech) => (
    79→            <button
    80→              key={tech.id}
    81→              onClick={() => select(tech)}
    82→              className="w-full text-left px-4 py-3 hover:bg-slate-50 transition-colors first:rounded-t-lg last:rounded-b-lg"
    83→            >
    84→              <p className="text-sm font-medium text-slate-800">{tech.name}</p>
    85→              <p className="text-xs text-slate-400 mt-0.5">
    86→                {tech.description} · {tech.patent_count?.toLocaleString()} patents
    87→              </p>
    88→            </button>
    89→          ))}
    90→        </div>
    91→      )}
    92→    </div>
    93→  );
    94→};
